  ('social-worker-moex-02251', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '臺灣因國際地位特殊，近年來多次以制定「施行法」之方式，將國際公約國內法化，請問以下何者尚未 制定施行法？', '["身心障礙者權利公約", "聯合國老人綱領", "消除對婦女一切形式歧視公約", "聯合國反貪腐公約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "89b4d02ec516", "answer_pdf_sha1": "12ce7bac1046", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02252', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '老人福利法第41條第3項規定：直轄市、縣（市）主管機關依老人申請或職權予以適當短期保護及安置， 所需費用由主管機關先行支付者，得檢具費用單據影本及計算書，通知義務人償還。所謂義務人依法為 下列何者？', '["老人之直系血親卑親屬或依契約有扶養義務者", "老人之配偶", "老人之兄弟姊妹", "老人之共同生活者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "89b4d02ec516", "answer_pdf_sha1": "12ce7bac1046", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02253', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '社工員A想知悉某協會發起全國性「散播希望計畫」之「勸募活動財物使用計畫書」，請問應造訪衛生 福利部何單位之網頁？', '["衛生福利部社會及家庭署", "衛生福利部保護服務司", "衛生福利部社會救助及社工司", "衛生福利部護理及健康照護司"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "89b4d02ec516", "answer_pdf_sha1": "12ce7bac1046", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02254', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '以下法規之修正，何者不須經由立法院三讀通過？', '["老人福利法", "社會救助法", "特殊境遇家庭扶助條例", "校園性侵害性騷擾或性霸凌防治準則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "89b4d02ec516", "answer_pdf_sha1": "12ce7bac1046", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02255', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列我國身心障礙福利機構相關規定的敘述，何者錯誤？', '["私人或團體設立身心障礙福利機構應辦理財團法人登記，始得接受補助", "各級主管機關應定期輔導、查核及評鑑身心障礙福利機構，評鑑結果分為優、甲、乙、丙、丁五個等第", "身心障礙福利機構經評鑑結果為丙等及丁等者，主管機關應輔導其改善", "小型設立之身心障礙福利機構得免辦理財團法人登記，但不能接受政府補助，只能自行募款"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "89b4d02ec516", "answer_pdf_sha1": "12ce7bac1046", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02256', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '請問依據我國的社會救助法，在計算家庭總收入時，下列何者不列入應計算人口範圍？', '["同一戶籍或共同生活之祖父母", "認列綜合所得稅扶養親屬免稅額之納稅義務人", "設有戶籍之非本國籍配偶或大陸地區配偶", "未共同生活且無扶養能力之已結婚兒女"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "89b4d02ec516", "answer_pdf_sha1": "12ce7bac1046", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02257', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '社會民主理論認為評量福利國家發展的重要指標是「去商品化」，請問關於此一概念的敘述，下列何者 錯誤？', '["去商品化可增加工人對抗資本的權力資源，促成勞資權力關係的平衡", "去商品化使工人生活需求的滿足成為一種公民權", "去商品化是指降低勞動力成為商品的程度，勞工不需依賴在勞動市場中販賣勞動力以維持生存", "提供工人社會保險是達成去商品化的最有效社會政策"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "89b4d02ec516", "answer_pdf_sha1": "12ce7bac1046", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02258', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '請問依據我國104年修正後的社會救助法，關於最低生活費的訂定，下列敘述何者比較正確？', '["最低生活費參照中央主計機關所公布當地區最近一年每人平均消費支出的百分之六十定之", "當新年度計算出的最低生活費數額較現行最低生活費變動達百分之五以上時調整之", "最低生活費數額不得超過中央主計機關所公布全國最近一年每人可支配所得平均數的百分之七十", "最低生活費不得低於臺灣省其餘縣（市）每人消費支出中位數的百分之六十"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "89b4d02ec516", "answer_pdf_sha1": "12ce7bac1046", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02259', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '請問依據我國的兒童及少年權益保障法施行細則，直轄市、縣（市）主管機關依照相關規定安置兒童及 少年時，應依循的優先順序原則為何？', '["依序是：親屬家庭、已登記合格的寄養家庭、經核准立案之兒童及少年安置及教養機構、其他安置機構", "依序是：親屬家庭、經核准立案之兒童及少年安置及教養機構、已登記合格的寄養家庭、其他安置機構", "依序是：經核准立案之兒童及少年安置及教養機構、已登記合格的寄養家庭、親屬家庭、其他安置機構", "依序是：經核准立案之兒童及少年安置及教養機構、親屬家庭、已登記合格的寄養家庭、其他安置機構"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "89b4d02ec516", "answer_pdf_sha1": "12ce7bac1046", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02260', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '請問依據我國的兒童及少年權益保障法施行細則，關於早期療育和發展遲緩兒童的相關規定，下列敘述 何者比較正確？', '["早期療育由社會福利、衛生、教育等專業人員以團隊方式提供", "早期療育是指依未滿十二歲的發展遲緩兒童及其家庭的個別需求，所提供的各項服務和照顧", "發展遲緩兒童是由社會福利主管機關確認的兒童福利機構評估確認，發給證明", "發展遲緩兒童的再評估時間，得由社工師視個案發展狀況建議之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "89b4d02ec516", "answer_pdf_sha1": "12ce7bac1046", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
